refsection.programlisting:
image = imread(fullpath(getIPCVpath() + "/images/opencv_smarties.png"));
rows = size(image, 1);
cols = size(image, 2);
[xx, yy] = meshgrid(1:cols, 1:rows);
[map1, map2] = imconvertmaps(xx, yy);
disp([map1(1, 1) map2(1, 1)]);

mapx = [0.1 1.2; 2.3 3.4];
mapy = [4.5 5.6; 6.7 7.8];
[map1, map2] = imconvertmaps(mapx, mapy, 16);
disp(map1);
disp(map2);
